import{_ as d,o as r,c as e,a4 as o}from"./chunks/framework.E9a65_Io.js";const s=JSON.parse('{"title":"岩石 🪨","description":"","frontmatter":{},"headers":[],"relativePath":"rock-🪨.md","filePath":"rock-🪨.md"}'),a={name:"rock-🪨.md"};function i(n,t,l,p,h,u){return r(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="岩石-🪨" tabindex="-1">岩石 🪨 <a class="header-anchor" href="#岩石-🪨" aria-label="Permalink to &quot;岩石 🪨&quot;">​</a></h1><p>岩石是世界一中生成深度在 8000 到 10000 米之间的地层矿石。可以传送到 9000 米深处，或者 26246.72 到 32808.4 英尺深处。它长这样：🪨🪨🪨🪨</p><p>🪨🪨🪨🪨🪨 包含以下矿石：</p><table tabindex="0"><thead><tr><th>矿石</th><th>基础稀有度</th><th>备注</th></tr></thead><tbody><tr><td>💠</td><td>1/6,000,000</td><td>（我不太信这个矿石）</td></tr><tr><td>⚜️</td><td>1/6,250,000</td><td></td></tr><tr><td>🥏</td><td>1/8,000,000</td><td></td></tr><tr><td>💍</td><td>1/15,000,000</td><td>可合成：💍×2 + 🥏×3 + 🤍×5 + 💚×10 + 🔵×50,000</td></tr><tr><td>🔋</td><td>1/36,000,000</td><td></td></tr><tr><td>🔮</td><td>1/60,000,000</td><td></td></tr><tr><td>☄️</td><td>1/72,500,000</td><td>（这 emoji 也太普通了）</td></tr><tr><td>💎</td><td>1/170,000,000</td><td>&quot;从深渊中出土，一颗耀眼的宝石浮现，向你投射出迷人的光芒……&quot;</td></tr><tr><td>🪷</td><td>1/183,640,000</td><td>&quot;在冬日寂静的孤独中，一颗冰之种子绽放，成为坚韧与重生的见证……&quot;</td></tr><tr><td>✨</td><td>1/240,800,000</td><td>&quot;从节日深处的每个角落，色彩如烟火般绽放在天鹅绒般的天空中……&quot;（呕，AI 写的 emoji）</td></tr><tr><td>🏝️</td><td>1/275,320,000</td><td>&quot;巨大闪耀的水晶从地面冒出，营造出一种短暂空灵的氛围……&quot;</td></tr><tr><td>❄️</td><td>1/386,500,000</td><td>&quot;你周围的世界呈现出超现实的质感，仿佛披上了冻结的寂静之袍……&quot;</td></tr><tr><td>🧊</td><td>1/583,000,000</td><td>&quot;一阵冰冷的触碰从深处带来冰封的拥抱……&quot;</td></tr><tr><td>🌈</td><td>1/2,750,000,000</td><td>&quot;一道鲜艳的光谱迸发而出，用绚烂的色彩描绘着周围的一切……&quot;</td></tr></tbody></table><p>（等一下兄弟们，我得去搞 Apatite，马上回来）</p><p>aa</p><p><strong>为什么它往下跳了两行</strong></p><h3 id="专家意见" tabindex="-1">专家意见 <a class="header-anchor" href="#专家意见" aria-label="Permalink to &quot;专家意见&quot;">​</a></h3><p>我咨询了著名地质学家 Oliver M.Eneral 关于在地下约 30,000 英尺处发现的岩石的性质。Oliver 对这个复杂的话题可能有很多话要说，但他只说了这么一句：</p><blockquote><p>&quot;它们是由均匀的无机化学成分组成的固体物质，具有晶体内部结构，并且是天然形成的。别再在我面前说&#39;岩石&#39;这个词；这是一个<a href="./god-of-the-mine-(gotm).html">矿洞之神</a>级别的超维概念！&quot;</p></blockquote><hr><p><em>由 <a href="https://the-silly-caverns.fandom.com/wiki/Rock_%F0%9F%AA%A8" target="_blank" rel="noreferrer">笨猫探穴 Wiki</a> 汉化</em></p>',12)])])}const _=d(a,[["render",i]]);export{s as __pageData,_ as default};
